head.script:
scwin.vCurDate = $c.date.getServerDateTime();  // 서버를 기준으로 현재 날짜 반환

scwin.tr_actionKind;  //조회/수정 구분
scwin.isBatch = 0;  //일괄생성작업여부
scwin.pos_rowSts = 0;  //현재 행저장
scwin.updBtnYn = false; // 수정 버튼 클릭 시 row 값 비교를 위한
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	ed_lineCd.setValue("SITC");
    ed_txt_lineNm.setValue("SITC CONTAINER LINES CO.,LTD.");

    $c.gus.cfDisableObjects([ed_lineCd]);
	$c.gus.cfDisableObjects([ed_txt_lineNm]);

    $c.gus.cfDisableObjects(tb_retrieveData);
    $c.gus.cfDisableBtn([btn_updateBatch, btn_update, btn_save]);

    //ed_lineCd.index = 0;
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    cal_doIssueDdDt.setInitDate(scwin.vCurDate, scwin.vCurDate);

    scwin.initComp();
};

scwin.initComp = function() {

    var codeObj = [ed_vsslCd];

    for (var i = 0 ; i < codeObj.length ; i++) {
        codeObj[i].unbind('onkeyup');
        codeObj[i].bind('onkeyup', function(e) {

            var obj = window[e.target.id];

            if (obj && obj.getValue) {

                var oldVal = obj._oldValue;
                var newVal = obj.getValue().toUpperCase();

                obj.setValue(newVal);
                obj._oldValue = oldVal;
            }
        });
    }
}

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tb_queryList, null);

    ed_lineCd.setValue("SITC");
    ed_txt_lineNm.setValue("SITC CONTAINER LINES CO.,LTD.");

    cal_doIssueDdDt.setInitDate(scwin.vCurDate, scwin.vCurDate);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = async function (e) {
    let rtn1 = await $c.gus.cfValidate([tb_queryList]);
    if( !rtn1 ) {
        return;
    }

    if(!$c.gus.cfValidate(doIssueDdStDt) || !$c.gus.cfValidate(doIssueDdEndDt)){
        return;
    }

    var afterDate = $c.gus.cfIsAfterDate(doIssueDdStDt.getValue(), doIssueDdEndDt.getValue());
    if( !afterDate ) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        doIssueDdStDt.focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);

};

scwin.sbm_retrieve_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        //HeadCheck 초기화
        //gr_list.ColumnProp('chk', 'HeadCheck') = "false";

        //일괄수정 외 일때 HeadCheckShow 히든처리
        //gr_list.ColumnProp('chk', 'HeadCheckShow') = false;

        let allData = ds_list.getAllJSON();

        for (let i = 0; i < allData.length; i++) {
            rowData = allData[i];
            if (rowData["gateOutDtm"].length == 0 && rowData["gateInDtm"].length == 0) {
                ds_list.setCellData(i, "gateOutDtm", null);
                ds_list.setCellData(i, "gateInDtm", null);
            }
            if (rowData["gateOutDtm"].length > 0 && rowData["gateInDtm"].length == 0) {
                ds_list.setCellData(i, "gateOutDtm", rowData["gateOutDtm"].substring(0,4) + "/" + rowData["gateOutDtm"].substring(4,6) + "/" + rowData["gateOutDtm"].substring(6,8));
                ds_list.setCellData(i, "gateInDtm", null);
            } else if (rowData["gateOutDtm"].length == 0 && rowData["gateInDtm"].length > 0) {
                ds_list.setCellData(i, "gateOutDtm", null);
                ds_list.setCellData(i, "gateInDtm", rowData["gateInDtm"].substring(0,4) + "/" + rowData["gateInDtm"].substring(4,6) + "/" + rowData["gateInDtm"].substring(6,8));
            } else if (rowData["gateOutDtm"].length > 0 && rowData["gateInDtm"].length > 0) {
                ds_list.setCellData(i, "gateOutDtm", rowData["gateOutDtm"].substring(0,4) + "/" + rowData["gateOutDtm"].substring(4,6) + "/" + rowData["gateOutDtm"].substring(6,8));
                ds_list.setCellData(i, "gateInDtm", rowData["gateInDtm"].substring(0,4) + "/" + rowData["gateInDtm"].substring(4,6) + "/" + rowData["gateInDtm"].substring(6,8));
            }
        };

        totalRows.setValue(ds_list.getRowCount());

        //조회결과가 0인경우
        if (ds_list.getRowCount() == 0) {
            $c.gus.cfDisableBtn([btn_updateBatch, btn_update, btn_save]);
            $c.gus.cfAlertMsg(MSG_CM_ERR_003);//("조회결과가 존재하지 않습니다.");
            return;
        } else {
            $c.gus.cfDisableBtn([btn_save]);
            $c.gus.cfEnableBtnOnly([btn_updateBatch, btn_update]);
        }

        //기존행 포커스
        gr_list.setFocusedCell(scwin.pos_rowSts, 0);

        //선택, 반출일자, 반납기한 수정불가능
        scwin.f_initEditable("N");
    }
};

//-------------------------------------------------------------------------
// 컬럼 수정여부 초기화
//-------------------------------------------------------------------------
scwin.f_initEditable = function (gubun) {
    switch(gubun) {
		case "Y" :
			//일괄수정일때 HeadCheckShow 보여줌
			//gr_list.ColumnProp('chk', 'HeadCheckShow') = true;
			//gr_list.ColumnProp('chk', 'Edit') = "any";
            gr_list.removeHeaderClass("column1", "dis-none");
            //gr_list.setColumnDisabled("chk", false);
            gr_list.setColumnReadOnly("chk", false);

			//컬럼EDIT설정(반출기한, 반납기한)
			//gr_list.ColumnProp('cntrCrryoutCloseDt', 'Edit') = 'Numeric';
			//gr_list.ColumnProp('cntrRtrnDt', 'Edit') = 'Numeric';
            gr_list.setColumnReadOnly("cntrCrryoutCloseDt", false);
            gr_list.setColumnReadOnly("cntrRtrnDt", false);
			break;
		case "N" :
			//일괄수정 외 일때 HeadCheckShow 가려줌
			//gr_list.ColumnProp('chk', 'HeadCheckShow') = false;
			//gr_list.ColumnProp('chk', 'Edit') = "none";
            gr_list.setHeaderClass("column1", "dis-none");
            //gr_list.setColumnDisabled("chk", true);
            gr_list.setColumnReadOnly("chk", true);

			//컬럼EDIT설정(반출기한, 반납기한)
			//gr_list.ColumnProp('cntrCrryoutCloseDt', 'Edit') = 'none';
			//gr_list.ColumnProp('cntrRtrnDt', 'Edit') = 'none';
            gr_list.setColumnReadOnly("cntrCrryoutCloseDt", true);
            gr_list.setColumnReadOnly("cntrRtrnDt", true);
			break;
	}
};

//-------------------------------------------------------------------------
// 필수항목/타이틀 변경
//-------------------------------------------------------------------------
scwin.f_mandatoryChange = function (flag) {

	if (flag == 1) {
		//반납지
		ed_arvWrkPlCd.options.mandatory = "true";
		ed_arvWrkPlCd.options.validExp = "반납지";  // :yes
	} else  {
		//반납지
		ed_arvWrkPlCd.options.mandatory = "false";
		ed_arvWrkPlCd.options.validExp = "반납지";  // :no
	}

	//mandatory항목을 다시 그린다.
	//cfRefreshMandSign();
}

//-------------------------------------------------------------------------
// 공통 팝업 오픈 - 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.udc_vsslCd_onviewchangeCodeEvent = function (info) {

    var val = ed_vsslCd.getValue().trim();

    ed_vsslCd.setValue('');
    txt_vsslNm.setValue('');

    if ( val == '') return;

    scwin.udc_vsslCd_openPopup('T', val, '');
};


scwin.udc_vsslCd_onviewchangeNameEvent = function (info) {

    var val = txt_vsslNm.getValue().trim();

    ed_vsslCd.setValue('');
    txt_vsslNm.setValue('');

    if ( val == '') return;

    scwin.udc_vsslCd_openPopup('T', '', val);
};

scwin.udc_vsslCd_onclickEvent = function (e) {

    var codeVal = ed_vsslCd.getValue().trim();
    var nameVal = txt_vsslNm.getValue().trim();

    scwin.udc_vsslCd_openPopup('F', codeVal, nameVal);
};

scwin.udc_vsslCd_openPopup = function (pClose, pCode, pName) {


    udc_vsslCd.cfCommonPopUp(scwin.udc_vsslCd_callBackFunc,  //SQL SELECT ID;
	                        pCode,  //조회조건 CODE;
	                        pName,  //조회조건 CODE_NAME;
	                        pClose, //1건일경우 자동 닫기 여부(T:자동닫기, F:보여주기);
	                        null,
	                        null,
	                        "120,200,0,0,0,0,0,0,0,0",
	                        null,
	                        null, //SQL WHERE조건에 들어가는 INPUT PARAMETER;
	                        null,
	                        null,
	                        null,
	                        null); 
};

scwin.udc_vsslCd_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) { 
        ed_vsslCd.setValue(rtnList[0]); // 코드
        txt_vsslNm.setValue(rtnList[1]); // 명
    }
    else {
        ed_vsslCd.setValue(""); // 코드
        txt_vsslNm.setValue(""); // 명
    }
};

//-------------------------------------------------------------------------
// 일괄수정
//-------------------------------------------------------------------------
scwin.btn_updateBatch_onclick = function (e) {
    scwin.tr_actionKind = "UPDATE";
    scwin.isBatch = 1;

    //선택, 반출일자, 반납기한 수정가능
    scwin.f_initEditable("Y");

    //버튼제어
    $c.gus.cfEnableBtnOnly([btn_save]);
    $c.gus.cfDisableBtn([btn_update, btn_updateBatch]);
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.btn_update_onclick = function (e) {
    scwin.tr_actionKind = "UPDATE";
    scwin.updBtnYn = true;
    scwin.isBatch = 0;
    $c.gus.cfEnableObjects([ica_ed_cntrCrryoutCloseDt, ica_ed_cntrRtrnDt]);

    //반납지가 있는 경우에만 수정가능하도록
    if (ed_arvWrkPlCd.getValue() != "") {
        $c.gus.cfEnableObjects([ed_arvWrkPlCd, txt_arvWrkPlNm, btn_arvWrkPlCd]);
        //반납지를 필수항목으로
        scwin.f_mandatoryChange(1);
    }

    //버튼제어
    $c.gus.cfEnableBtnOnly([btn_save]);
    $c.gus.cfDisableBtn([btn_update, btn_updateBatch]);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    //현재 행저장
    scwin.pos_rowSts = ds_list.getRowPosition();
 	var vRowStatus = ds_list.getRowStatusValue(ds_list.getRowPosition());

    if (vRowStatus == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("컨테이너 진행현황"));
        return false;
    }

    var chkCnt = 0;	//체크수
    for (var i = 0; i < ds_list.getRowCount(); i++) {
        if (ds_list.getCellData(i, "chk") == 1) {
            chkCnt++;
        }

        if ((ds_list.getCellData(i, "chk") == 1 && ds_list.getCellData(i, "cntrCrryoutCloseDt") == null)
            || (ds_list.getCellData(i, "chk") == 1 && ds_list.getCellData(i, "cntrCrryoutCloseDt") == "")) {
            $c.win.alert("반출기한은(는) 필수 입력 항목입니다.");
            return false;
        }

        if (ds_list.getCellData(i, "chk") == 1 && ds_list.getCellData(i, "cntrCrryoutCloseDt").length != 8) {
            $c.win.alert("반출기한은(는) 8자리수만큼 입력하십시오.");
            return false;
        }
    }

    if (scwin.isBatch == 1) {
        if (chkCnt == 0) {
            $c.win.alert("선택된 행이 없습니다. 저장하려는 데이터를 선택하세요.");
            return false;
        }
    }

    if (ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt") == null || ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt") == "") {
        $c.win.alert("반출기한은(는) 필수 입력 항목입니다.");
        return false;
    }

    if (ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt").length != 8) {
        $c.win.alert("반출기한은(는) 8자리수만큼 입력하십시오.");
        return false;
    }

    //Mandatory 항목이 누락하지 않았는지 체크한다.
    let ret1 = await $c.gus.cfValidate([tb_retrieveData]);
    if (!ret1) {
        return;
    }

    let ret2 = await $c.gus.cfValidate(ica_ed_cntrCrryoutCloseDt);
    if (!ret2) {
        return;
    }

    let confirm = await $c.win.confirm("저장하시겠습니까?");
    if( confirm ) {
        scwin.isBatch = "";
        //수정 + 저장
        dma_list.set("cntrCrryoutCloseDt", ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt"));
        dma_list.set("cntrRtrnDt", ds_list.getCellData(ds_list.getRowPosition(), "cntrRtrnDt"));
        dma_list.set("arvWrkPlCd", ds_list.getCellData(ds_list.getRowPosition(), "arvWrkPlCd"));

        //저장
        dma_list.set("doNo", ds_list.getCellData(ds_list.getRowPosition(), "doNo"));
        dma_list.set("blNo", ds_list.getCellData(ds_list.getRowPosition(), "blNo"));
        dma_list.set("doIssueDd", ica_ed_doIssueDd.getValue());
        dma_list.set("copinoId", ed_copinoId2.getValue());
        dma_list.set("callsignCd", ed_txt_callsignCd.getValue().toUpperCase());
        dma_list.set("vsslNm", ed_txt_vsslNm2.getValue().toUpperCase());
        dma_list.set("vsslPortcnt", ed_txt_vsslPortcnt.getValue().toUpperCase());
        dma_list.set("vsslArrvlportDtm", ica_ed_vsslArrvlportDtm.getValue());
        dma_list.set("cntrNo", ed_cntrNo2.getValue());
        dma_list.set("cntrNrm", ed_txt_cntrNrm.getValue().toUpperCase());
        dma_list.set("mrn", ed_txt_mrn.getValue().toUpperCase());
        dma_list.set("msn", ed_txt_msn.getValue());
        dma_list.set("dsmbrkPlcCd", ds_list.getCellData(ds_list.getRowPosition(), "dsmbrkPlcCd").toUpperCase());
        dma_list.set("dropPort", ed_txt_dropPort.getValue().toUpperCase());
        dma_list.set("dchrPort", ed_txt_dchrPort.getValue().toUpperCase());
        dma_list.set("sendMchtNm1", ed_txt_sendMchtNm1.getValue().toUpperCase());
        dma_list.set("cntMchtNm", ed_txt_cntMchtNm.getValue().toUpperCase());
        dma_list.set("rmkDesc", ed_txt_rmkDesc.getValue());

        if (scwin.tr_actionKind == "INSERT") {
            $c.sbm.execute(sbm_insert);
        } else if (scwin.tr_actionKind == "UPDATE") {
            $c.sbm.execute(sbm_update);
        }
    }
};

scwin.sbm_update_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다
        $c.gus.cfDisableObjects(tb_retrieveData);
        scwin.btn_retrieve_onclick();
    }
};

scwin.sbm_insert_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다
        $c.gus.cfDisableObjects(tb_retrieveData);
        scwin.btn_retrieve_onclick();
    }
};

scwin.gr_list_onheaderclick = function (headerId) {
	var cr = ds_list.getRowCount();
	//행이 0보다 크고, B/L, CNTR_NO항목이 NULL이 아닐 경우에만 체크 가능
    var check = gr_list.getHeaderValue("column1");
	if (cr > 0) {
		if (headerId == "column1" && check == 1) {
			for (var i = 0; i < cr; i++) {
				if (ds_list.getCellData(i, "blNo") != "" && ds_list.getCellData(i, "cntrNo") != "") {
					ds_list.setCellData(i, "chk", 1);
					//상태를 UPDATE로 변경한다.
					ds_list.modifyRowStatus(i, "U");  //UPDATE(3)
				}
			}
		}

		if (headerId == "column1" && check == 0) {
			for (var i = 0; i < cr; i++) {
				if (ds_list.getCellData(i, "blNo") != "" && ds_list.getCellData(i, "cntrNo") != "") {
					ds_list.undoRow(i);
				}
			}
		}
	}
};

scwin.gr_list_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.updBtnYn = false;
	var vCountRow = ds_list.getRowCount();

    if( vCountRow > 0  && scwin.isBatch == 0) {
        $c.gus.cfEnableBtnOnly([btn_update, btn_updateBatch]);
        if (!scwin.updBtnYn) {
            $c.gus.cfDisableObjects([ica_ed_cntrCrryoutCloseDt, ica_ed_cntrRtrnDt]);
            $c.gus.cfDisableBtnOnly([btn_save]);
        }
    } else {
        $c.gus.cfDisableBtnOnly([btn_update, btn_updateBatch]);
        $c.gus.cfEnableBtnOnly([btn_save]);
    }

    let check = ds_list.getCellData(rowIndex, "chk");
	if (columnId == "chk" && check == 1) {
		if (ds_list.getCellData(rowIndex, "blNo") != "" && ds_list.getCellData(rowIndex, "cntrNo") != "") {
			ds_list.setCellData(rowIndex, "chk", 1);
			//상태를 UPDATE로 변경한다.
			ds_list.modifyRowStatus(rowIndex, "U");  //UPDATE(3)
		} else {
			$c.gus.cfAlertMsg("B/L번호와 컨테이너번호가 존재하지 않아  체크할 수 없습니다.");
			ds_list.undoRow(rowIndex);
		}
	}

	if (columnId == "chk" && check == 0) {
		if (ds_list.getCellData(rowIndex, "blNo") != "" && ds_list.getCellData(rowIndex, "cntrNo") != "") {
			ds_list.undoRow(rowIndex);
		}
	}
};

scwin.ica_ed_cntrCrryoutCloseDt_onchange = function () {
    //반출기한을 수정하였을 때 Org값과 비교하여 변경되었다면 체크박스를 체크한다.
    var val = ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt");
	var orgVal = ds_list.getOriginalCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt");
	var val2 = ds_list.getCellData(ds_list.getRowPosition(), "cntrRtrnDt");
	var orgVal2 = ds_list.getOriginalCellData(ds_list.getRowPosition(), "cntrRtrnDt");
	//console.log("### ica_ed_cntrCrryoutCloseDt_onchange : "+val+" :: "+orgVal);

	if ((val != orgVal) || (val2 != orgVal2)) {
		ds_list.setCellData(ds_list.getRowPosition(), "chk", 1);
	} else {
		ds_list.setCellData(ds_list.getRowPosition(), "chk", 0);
	}
};

scwin.ica_ed_cntrRtrnDt_onviewchange = function (info) {
    //반납기한을 수정하였을 때 Org값과 비교하여 변경되었다면 체크박스를 체크한다.
    var val = ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt");
	var orgVal = ds_list.getOriginalCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt");
	var val2 = ds_list.getCellData(ds_list.getRowPosition(), "cntrRtrnDt");
	var orgVal2 = ds_list.getOriginalCellData(ds_list.getRowPosition(), "cntrRtrnDt");
	//console.log("### ica_ed_cntrRtrnDt_onviewchange : "+val2+" :: "+orgVal2);

	if ((val != orgVal) || (val2 != orgVal2)) {
		ds_list.setCellData(ds_list.getRowPosition(), "chk", 1);
	} else {
		ds_list.setCellData(ds_list.getRowPosition(), "chk", 0);
	}
};

scwin.ed_doNo_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.ed_mrn_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.ed_cntrNo_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.f_toExcel = function (e) {
    $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?", scwin.toExcelCallBack);
};

scwin.toExcelCallBack = function (e) {
    if (e.clickValue) {
        let options = {
            fileName: "Sitc 반출입 관리 현황.xlsx",
            sheetName: "Sitc 반출입 관리 현황",
            type: "1",
            useStyle: "true"
        };
        $c.data.downloadGridViewExcel(gr_list, options);
    };
};
